Javascript.validate:
// defect uct 577 - - MGG 28/04/2006
var dateOfHearing = Services.getValue(DateOfHearing.dataBinding);
var dateOfHearingObj = CaseManUtils.isBlank(dateOfHearing) ? null : CaseManUtils.createDate(dateOfHearing);
var ec = null;
if(dateOfHearingObj != null){
  ec = validateHearingDate(dateOfHearingObj);     
}
return ec;

Javascript.miscCode:
function validateHearingDate(dateObj)
{    
  var todayDateObj = CaseManUtils.createDate(getTodaysDate());
  var errCode = null;
  var comparison = CaseManUtils.compareDates(dateObj, todayDateObj);
  if(comparison == 1 || comparison == 0){
    errCode = ErrorCode.getErrorCode("CaseMan_dateCanOnlyBeInTheFuture_Msg");
  }     
  return errCode;   
}
